function highlight(strings: TemplateStringsArray, ...values: any[]): string {
  return strings.reduce((result, str, i) => {
    const val = values[i] !== undefined ? `<strong>${values[i]}</strong>` : '';
    return result + str + val;
  }, '');
}

const user = 'Alice';
const score = 98;
console.log(highlight`User ${user} scored ${score} points.`);
// "User <strong>Alice</strong> scored <strong>98</strong> points."

@Injectable({ providedIn: 'root' })
export class UserService {
  private readonly base = '/api/v1';

  constructor(private http: HttpClient) {}

  getUser(id: number) {
    return this.http.get<User>(`${this.base}/users/${id}`);
  }

  getUserPosts(userId: number, page = 1) {
    return this.http.get<Post[]>(`${this.base}/users/${userId}/posts?page=${page}`);
  }
}

