function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function html(strings: TemplateStringsArray, ...values: unknown[]): string {
  return strings.reduce((result, str, i) => {
    const raw = values[i];
    // Escape strings; pass numbers/booleans through
    const safe =
      raw === undefined ? '' :
      typeof raw === 'string' ? escapeHtml(raw) :
      String(raw);
    return result + str + safe;
  }, '');
}

