function dedent(strings: TemplateStringsArray, ...values: unknown[]): string {
  const raw = strings.reduce((r, s, i) => r + s + (values[i] ?? ''), '');
  const lines = raw.split('\n');
  // Remove empty first/last lines from the surrounding newlines
  const trimmed = lines.filter((_, i) => !(i === 0 || i === lines.length - 1) || lines[i].trim());
  const indent = Math.min(
    ...trimmed.filter(l => l.trim()).map(l => l.match(/^(\s*)/)?.[1].length ?? 0)
  );
  return trimmed.map(l => l.slice(indent)).join('\n').trim();
}

