// A minimal parameterised SQL builder using tagged templates
interface SqlQuery { text: string; values: unknown[]; }

function sql(strings: TemplateStringsArray, ...values: unknown[]): SqlQuery {
  const text = strings.reduce((q, s, i) =>
    q + s + (i < values.length ? `$${i + 1}` : ''), '');
  return { text, values };
}

// Usage
const userId = 42;
const role   = 'admin';
const query  = sql`SELECT * FROM users WHERE id = ${userId} AND role = ${role}`;
// { text: 'SELECT * FROM users WHERE id = $1 AND role = $2',
//   values: [42, 'admin'] }
// The values are never concatenated into the query string -- safe from SQL injection

// Type-safe route builder
type RouteParams = Record<string, string | number>;

function route(strings: TemplateStringsArray, ...keys: string[]): (params: RouteParams) => string {
  return (params) =>
    strings.reduce((r, s, i) => r + s + (params[keys[i]] ?? ''), '');
}

const userRoute     = route`/users/${':id'}`;
const userPostRoute = route`/users/${':userId'}/posts/${':postId'}`;

console.log(userRoute({ ':id': 7 }));                       // '/users/7'
console.log(userPostRoute({ ':userId': 7, ':postId': 22 })); // '/users/7/posts/22'

describe('UserService URL building', () => {
  let service: UserService;
  let http: jasmine.SpyObj<HttpClient>;

  beforeEach(() => {
    http    = jasmine.createSpyObj('HttpClient', ['get']);
    service = new UserService(http as any);
  });

  it('builds the correct user URL', () => {
    http.get.and.returnValue(of(null));
    service.getUser(42).subscribe();
    // The template literal resolves to a plain string at call-time
    expect(http.get).toHaveBeenCalledWith('/api/v1/users/42');
  });

  it('includes page param in post URL', () => {
    http.get.and.returnValue(of([]));
    service.getUserPosts(7, 3).subscribe();
    expect(http.get).toHaveBeenCalledWith('/api/v1/users/7/posts?page=3');
  });

  it('defaults page to 1', () => {
    http.get.and.returnValue(of([]));
    service.getUserPosts(7).subscribe();
    expect(http.get).toHaveBeenCalledWith('/api/v1/users/7/posts?page=1');
  });
});

// Testing a tagged template
describe('html tag', () => {
  it('escapes user-supplied strings', () => {
    const unsafe = '<img src=x onerror=alert(1)>';
    const result = html`<p>${unsafe}</p>`;
    expect(result).not.toContain('<img');
    expect(result).toContain('&lt;img');
  });

  it('passes numbers through unescaped', () => {
    const count = 42;
    expect(html`<span>${count}</span>`).toBe('<span>42</span>');
  });
});
